const item = $input.first().json;

// Detect city from URL or address
function extractCity(url, address) {
  const CITY_MAP = [
    ['cascais','Cascais'],['sintra','Sintra'],['estoril','Estoril'],
    ['lisboa','Lisboa'],['lisbon','Lisboa'],
    ['porto','Porto'],['foz-do-douro','Porto'],
    ['faro','Algarve'],['vilamoura','Algarve'],['albufeira','Algarve'],
    ['lagos','Algarve'],['portimao','Algarve'],
    ['comporta','Comporta'],['setubal','Setúbal'],
    ['madeira','Madeira'],['funchal','Madeira'],
    ['acores','Açores'],['ponta-delgada','Açores'],
  ];
  const haystack = `${url} ${address}`.toLowerCase();
  for (const [k, v] of CITY_MAP) {
    if (haystack.includes(k)) return v;
  }
  return null;
}

// Detect tipo_ativo
function extractTipo(url, titulo) {
  const h = `${url} ${titulo}`.toLowerCase();
  if (h.includes('moradia') || h.includes('vivenda')) return 'moradia';
  if (h.includes('predios') || h.includes('predio') || h.includes('edificio')) return 'prédio';
  if (h.includes('terrenos') || h.includes('terreno')) return 'terreno';
  if (h.includes('hotel')) return 'hotel';
  if (h.includes('loja') || h.includes('comercial')) return 'comercial';
  if (h.includes('apartamento') || h.includes('casas')) return 'apartamento';
  return 'apartamento';
}

const listingId = item.url?.match(/\/([0-9]+)\/?$/)?.[1] ?? item.id ?? item.listingId;

return [{ json: {
  source: 'apify_idealista',
  source_listing_id: String(listingId),
  source_url: item.url,
  nome: `Proprietário Idealista ${listingId}`,
  tipo_ativo: extractTipo(item.url ?? '', item.titulo ?? item.title ?? ''),
  localizacao: item.zona ?? item.bairro ?? item.address ?? null,
  cidade: extractCity(item.url ?? '', item.address ?? ''),
  area_m2: typeof item.area === 'number' ? item.area : typeof item.areaM2 === 'number' ? item.areaM2 : null,
  price_ask: typeof item.price === 'number' ? item.price : typeof item.preco === 'number' ? item.preco : null,
  contacto: item.contacto ?? item.phone ?? item.agencyName ?? null,
  urgency: (item.priceDropPercentage > 0 || (item.daysOnline ?? 0) > 90) ? 'high' : 'unknown',
  status: 'new',
  raw_data: item
}}];
